command.text:
&CheckLockedBeforeUpdate;
if not exists(select * from @@table where ngay = $ngay.OldValue and gio = $gio.OldValue and hs_yn = $hs_yn.OldValue and stt_rec = $stt_rec.OldValue) begin select 'ngay' as field, @$recordHasBeenChanged as message return end
if @ngay <> $ngay.OldValue or @gio <> $gio.OldValue or @hs_yn <> $hs_yn.OldValue or @stt_rec <> $stt_rec.OldValue begin if exists(select * from @@table where (not (ngay = $ngay.OldValue and gio = $gio.OldValue and hs_yn = $hs_yn.OldValue and stt_rec = $stt_rec.OldValue)) and (ngay = @ngay and gio = @gio and hs_yn = @hs_yn and stt_rec = @stt_rec)) begin select 'ngay' as field, @$exists as message return end end

script.text:
      /* <flatten type="Javascript"> */
function active$EmployeeTimeInOutAdjusting(f) {f.add_onResponseComplete(on$EmployeeTimeInOutAdjusting$ResponseComplete);}
function onchange$EmployeeTimeInOutAdjusting$IDNumber(o) {o.parentForm.request('IDNumber', 'IDNumber', ['ma_nv']);}
function close$EmployeeTimeInOutAdjusting(f) {try {f.remove_onResponseComplete(on$EmployeeTimeInOutAdjusting$ResponseComplete)} catch (ex) {}}
function on$EmployeeTimeInOutAdjusting$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'IDNumber':
      f.setItemControlBehavior('stt_rec', result[0].Value, true);
      break;
    default:
      break;
  }
}
/* </flatten> */
